func UpdatedAtLT(v time.Time) predicate.ModLog {
	return predicate.ModLog(sql.FieldLT(FieldUpdatedAt, v))
}

// UpdatedAtLTE applies the LTE predicate on the "updated_at" field.
func UpdatedAtLTE(v time.Time) predicate.ModLog {
	return predicate.ModLog(sql.FieldLTE(FieldUpdatedAt, v))
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ModLog) predicate.ModLog {
	return predicate.ModLog(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ModLog) predicate.ModLog {
	return predicate.ModLog(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ModLog) predicate.ModLog {
	return predicate.ModLog(sql.NotPredicates(p))
}
